42	const premiumForItem = (item: Item, customer: Customer): number => {
43	  const base = basePremiumForItem(item);
44	  return (
45	    base +
46	    surcharge(base, isCursed(item), CURSED_SURCHARGE_RATE) +
47	    surcharge(base, isHighlyEnchanted(item), HIGH_ENCHANTMENT_SURCHARGE_RATE) +
48	    surcharge(base, isNewcomer(customer), NEWCOMER_PER_ITEM_SURCHARGE_RATE)
49	  );
50	};
