64	const groupByType = (items: Item[]): Map<string, Item[]> => {
65	  const groups = new Map<string, Item[]>();
66	  for (const item of items) {
67	    const list = groups.get(item.type) ?? [];
68	    list.push(item);
69	    groups.set(item.type, list);
70	  }
71	  return groups;
72	};
73	
74	const componentsTotal = (items: Item[], customer: Customer): number => {
75	  const groups = groupByType(items);
76	  let total = 0;
77	  for (const groupItems of groups.values()) {
78	    const groupBase = componentGroupBase(groupItems);
79	    total +=
80	      groupBase +
81	      surcharge(
82	        groupBase,
83	        isNewcomer(customer),
84	        NEWCOMER_PER_ITEM_SURCHARGE_RATE,
85	      );
86	  }
87	  return total;
88	};
