90	export const quote = (input: QuoteInput): { premium: number } => {
91	  const components = input.items.filter(isComponent);
92	  const nonComponents = input.items.filter((item) => !isComponent(item));
93	  const nonComponentsTotal = nonComponents.reduce(
94	    (sum, item) => sum + premiumForItem(item, input.customer),
95	    0,
96	  );
97	  const itemsTotal =
98	    nonComponentsTotal + componentsTotal(components, input.customer);
99	  return { premium: Math.ceil(itemsTotal + PROCESSING_FEE) };
100	};
